__sys.getRmb = function(n, f, l) {
	var s = parseFloat(n);
	var r_rmb = /(\d)(?=(\d{3})+($|\.))/g;
	s = s.toFixed(l !== undefined ? l: ((s + '').indexOf('.') > 0 ? 2 : 0)).toString().split('.');
	s[0] = s[0].replace(r_rmb, '$1,');
	return (f ? '\uffe5': '') + s.join('.');
};

