__define('Counts', function(){
	//3.1 单式 401
	//3.2 复式 402
	//3.3 混投 408
	return {
		//计算选项注数和金额
		getOptsNum: function(data){
			__require('zccount');
			var lotid = __sys.get('lotid') || 1;
			var singleprice = 2;
			var len = (function(data){
				var i, length = 0;
				for(i in data){
					length++;
				}
				return length;
			})(data);
			var istrue = false,
				zs = 1,
				dftype = '单式',
				ln, 
				cid, 
				playid,
				olen = [],
				code = [],
				res = false;
			if(data && typeof data == 'object'){
				if(lotid == 17 && len == 8){ //四场进球
					istrue = true;
					res = {};
					playid = 399;
				}else if(lotid == 15 && len == 12){ //六场半全场
					istrue = true;
					res = {};
					playid = 401;
				}
				if(istrue){
					for (var i in data){
						cid = i;
						ln = data[i].length;
						olen[i-1] = [ln];
						code[cid-1] = data[i].join('');
						if(lotid == 17){
							if(playid == 399 && (ln > 1)){
								playid = 400;
								dftype = '复式';
							}
						}else{
							if(playid == 401 && ln > 1){
								playid = 402;
								dftype = '复式';
							}
						}
					}
					zs = __sys.libs.zccount(olen);
					res.zs = zs;
					res.dftype = dftype;
					res.money = (zs * singleprice).toFixed(2);
					res.playid = playid;
					res.code = code.join(',');
				}
				return res;
			}
			return false;
		}
	};
});
__defineClass('Utils', function() {
	function toJSON(e) {
		var g, a = [];
		switch (e.constructor) {
			case Object:
				$.each(e,
					function(f, g) {
						a.push('"' + f + '":' + toJSON(g));
					});
				return "{" + a.join(",") + "}";
			case Array:
				for (var c = 0,
						b = e.length; c < b; c++) {
					g = e[c];
					a.push(toJSON(g));
				}
				return "[" + a.join(",") + "]";
			case Number:
				return e.toString();
			default:
				return '"' + e.toString() + '"';
		}
	}
	return {
		//转换为json数据
		toJSON: toJSON,
		c: function(m, n) {
			var a, b, c;
			a = b = c = 1;
			for (; c <= n;) {
				b *= c++;
				a *= m--;
			}
			return Math.abs(a / b);
		},
		dt: function(d, t, m) {
			return d >= m ? 0 : this.c(t, m - d);
		},
		//打乱数组中的数据，让数组变成随机
		random: function(a) {
			//取得长度
			var j = a.length;
			a.forEach(function(v, i) {
				var n = Math.floor(Math.random() * j);
				a[i] = a[n];
				a[n] = v;
			});
			return a;
		},
		getByteLength: function(s) {
			return s.replace(/[^\x00-\xff]/g, '--').length;
		}
	};
