__defineClass('CodeBasket', function(){
	//加载数字模块
	__require('Number');
	//号码篮中每一条数据的模板
	var lineTmpl = '<tr data-index="{index}">'+
						'<td><span class="list-del" title="删除" data-click="remove($el)">删除</span></td>'+
						'<td align="left" class="list-num ff-arial">'+
							'<span class="list-num-main">{code}</span>'+
							'<span class="list-num-info">[ {dftype}{zs}注 {money}元 ]</span>'+
						'</td>'+
						'<td><span class="list-modefy" data-click="modify($el)">修改</span></td>'+
					'</tr>';
	//总的金额和注数的模板
	var sumTmpl = '总金额&nbsp;&nbsp;<em class="red f18 ff-arial">{allmoney}<span class="f-14">元</span></em>&nbsp;&nbsp;<span class="gray">({allzs}注)</span>';
	return {
		ui:{
			'{root}':{
				bind: 'data-click',
				name: 'root',
				'onclick .c-rst-ok>a.btn-red': 'getCode($el)', //选好了
				'onclick a.btn-white': 'clearCode($el)' //清空列表
			},
			'#cResult':{
				'.numsel': {
					init: function(el) {
						//倍数输入框
						this.bsInput = this.libs.Number({
							root: el,
							defaultValue: this.get('multiple'),
							max: 999,
							autoSelect: true
						}).on('value.change', function(multiple) {
							this.set('multiple', multiple);
							this.showSum();
						},this).on('beforeChange', function(v) {
							/*var money = this.get('allmoney');
							var maxCanBuy = __sys.get().maxBuy;
							if (money*v > maxCanBuy) {
								__sys.alert('您好， 单个方案金额不能超过' + maxCanBuy + '元， 请调整投注方案');
								return false;
							}*/
						}, this);
					}
				}
			},
			//投注框显示
			'#codeTable': {
				html: 'codetable'
			},
			//总金额倍数显示
			'.info-money-je': {
				html: 'summoney'
			}
		},
		defaults:{
			//存放号码的号码篮
			codes:[],
			//该订单的金额总数
			allmoney:0,
			//该订单的总注数
			allzs:0,
			//号码的索引
			index:0,
			//该方案的倍数
			multiple:1,
			//保存修改的数据
			modifyData: false,
			//号码蓝显示
			codetable: '',
			//号码篮最大选号行
			maxLine: 100,
			//要修改的某一条数据的金额
			modefymoney:0
		},
		events:{
			'codes.change': function(){
				//对于密集操作，只有最后一次操作有效
				clearTimeout(this.dataChangeId);
				this.dataChangeId = setTimeout(this.bind(this.update), 1);
			}
		},
		remove: function(el){
			var code = $(el).parent().parent();
			//获取该注的索引
			var index = parseInt(code.attr('data-index'),10);
			//删除该数组中的元素
			this.removeCode(index);
			//删除该元素
			code.remove();
		},
		modify: function(el){
			var code, _T = this;
			var codeArea = $(el).parent().parent();

			//获取该注的索引
			var index = parseInt(codeArea.attr('data-index'),10);
			//动画
			$('body,html').animate({
				scrollTop: $('div.main').offset().top
			});
			$(codeArea).parent().find('tr').removeClass('cur');
			//添加选中效果
			codeArea.addClass('cur');
			//修改
			code = this.get('codes').map(function(el, i){
				if(el.index == index){
					_T.set('modifyData', el);
					return el.code;
				}
			}).join('');
			this.options.choose.modifyCode(code);
			var res = __require('Counts').getOptsNum(this.options.choose.get('data'));
			this.set('modefymoney', res.money);
		},
		//删除一注码
		removeCode: function(index){
			var codes = this.get('codes',[]);
			for(var i=0; i<codes.length; i++){
				if(codes[i].index === index){
					//减去相应的钱
					this.set('allmoney', this.get('allmoney') - codes[i].money);
					this.set('allzs', this.get('allzs') - codes[i].zs);
					//删除一个元素
					codes.splice(i,1);
					this.showSum();
                    //判断删除的选项是否为修改的选项
                    if(this.get('modifyData') !== false && this.get('modifyData').index == index){
                        this.set('modifyData', false);
                    }
					break;
				}
			}
			this.update();
		},
		//获取投注号码
		getCode: function(el){
			var _T = this;
			var _code;
			var code = this.options.choose.get();
			if(!code.zs){
				return __sys.alert('请至少选择6场完整的比赛');
			}
			_code = {
				code: code.code, 
				playid: code.playid, 
				zs: code.zs, 
				money: parseInt(code.zs*2, 10), 
				dftype: code.dftype
			};
			var allmoney = this.get('allmoney');
			var maxCanBuy = __sys.get().maxBuy;
			var modefymoney = this.get('modefymoney');
			//判断是否是修改
			if(this.get('modifyData') !== false){
				//判断单个方案是否超过限额
				if((allmoney+_code.money-parseInt(modefymoney, 10))*this.get('multiple') > maxCanBuy){
					__sys.alert('您好， 单个方案金额不能超过' + maxCanBuy + '元， 请调整投注方案');
					return false;
				}
			}else{
				//判断单个方案是否超过限额
				if((allmoney+code.zs*2)*this.get('multiple') > maxCanBuy){
					__sys.alert('您好， 单个方案金额不能超过' + maxCanBuy + '元， 请调整投注方案');
					return false;
				}
			}
			var basketcode_len = this.get('codes').length;
			if(this.get('modifyData') === false){
				//if(basketcode_len > this.get().maxLine){
				//	return __sys.alert('很抱歉，最多可选'+this.get().maxLine+'组号码');
				//}
				this.get('codes').push(_code);
			}
			var basketcode = [];
			this.get('codes').forEach(function(c, i){
				if(_T.get('modifyData') !== false && _T.get('modifyData').index == c.index){
					_code.index = i;
					basketcode.push(_code);
				}else{
					c.index = i;
					basketcode.push(c);
				}
			});
			this.set('codes', basketcode);
			this.set('modifyData', false);
			$('body,html').animate({
				scrollTop: $('div.main').offset().top
			});
			this.update();
			this.options.choose.clearchoose();
			this.options.choose.updateTzbl();
			this.options.choose.updateshebtn();
		},
		//清空列表
		clearCode: function(el){
			var _T = this;
			if(this.get('codes').length > 0){
				if(el == 'success'){
                    _T.set('codes', []);
                    _T.set('modifyData', false);
                    _T.update();
                }else{
                    __sys.confirm({html: '确定清空投注列表吗？'}, this.bind(function (ok){
                        if (ok) {
                            _T.set('codes', []);
                            _T.set('modifyData', false);
                            _T.update();
                        }
                    }));

                }		    
			}
		},
		//显示号码蓝投注号码
		showBasket: function(codetable){
			this.set('codetable', codetable, true);
		},
		//显示总金额和注数
		showSum: function(){
			var allmoney = this.get('allmoney')*this.get('multiple');
			this.set('summoney', __sys.format(sumTmpl, {allmoney: __sys.getRmb(allmoney, false, 2), allzs: this.get('allzs')}));
		},
		//更新投注内容
		update: function(){
			var codetable = '';
			var allmoney = 0, allzs = 0;
			if(this.get('codes').length > 0){
				codetable = this.get('codes').map(function(data, i){
					allmoney += parseInt(data.money, 10);
					allzs += parseInt(data.zs, 10);
					return __sys.format(lineTmpl,{
						index: data.index,
						code: (function(code){
							var codestr = '';
							code.split(',').forEach(function(el,i){
								if(i%2){
									if(i == code.split(',').length-1){
										codestr += el;
									}else{
										codestr += el + ' | ';
									}
								}else{
									codestr += el + ',';
								}
							});
							return codestr;
						})(data.code),
						dftype: data.dftype,
						zs: data.zs,
						money: data.money
					});
				}).join('');
			}
			this.set('allzs', allzs);
			this.set('allmoney', allmoney);
			this.showBasket(codetable);
			this.showSum();
		}
	};
});

