					'color':'red',
					'fontWeight' : 'bold'
				});
			}else{
				el.html('保存方案').removeClass(d);
			}
		},
		getData: function(){
			var data = {}, beishu = 1, money = 0, allmoney = 0, zhushu = 0, allzs = 0, codes = '', playArr = [];
			zhushu = this.options.codebasket.get('allzs');
			beishu = this.options.codebasket.get('multiple');
			money = this.options.codebasket.get('allmoney');
			codes = this.options.codebasket.get('codes');
			codes.forEach(function(code, i){
				allzs += code.zs;
				allmoney += code.money;
				if(playArr.indexOf(code.playid) == -1){
					playArr.push(code.playid);
				}
			});
			if(allmoney != money || allzs != zhushu){
				return __sys.alert('金额注数错误，请重新投注');
			}
			//返回数据
			data.lotid = parseInt($.trim($('#lotid').val()), 10);
			data.expect = parseInt($.trim($('#expect').val()), 10);
			data.beishu = beishu;
			data.zhushu = zhushu;
			data.allmoney = parseInt(money*beishu, 10);
			data.playid = playArr.length>1?408:playArr[0];
			data.codes = this.getFormatCode(codes, data.playid);
			data.vs = this.getVsList();
			data.line = codes.length;
			data.isusehb = parseInt($.trim($('#isusehb').val()), 10);
			if(data.codes){
				this.set('noCode', false); 
			}else{
				this.set('noCode', true); 
			}
			return data;
		},
		//获取对阵列表
		getVsList: function(){
			var vslist = [];
			this.ui_vstable.find('tr.bet-tb-tr').each(function(i, el){
				vslist.push($.trim($(el).attr('data-vs')));
			});
			return vslist.join('$');
		},
		//生成投注号码
		getFormatCode: function(codes, playid){
			if(!codes || codes.length === 0){ return '';}
			return codes.map(function(el, i){
				if(playid == 408){
					return el.code+'#'+el.playid;
				}else{
					return el.code;
				}
			}).join('$');
		},
		//点击提交
		tobuy: function(el) {
			//判断是否可点击
			if($(el).hasClass('btn-red-off')){
				return false;
			}
			//预售期          
			if(__sys.get('zc.issave')!=1){
				return __sys.alert('本期尚未开售，暂不支持保存方案');
			}
			//获取投注内容
			var data = this.getData();
			//判断是否有注数
			if (this.get().noCode) {
				return __sys.alert('您好，请至少选择1注号码再进行购买');
			}
			//购买确认层
			var _T = this;
			__sys.checkLogin(function() {
				var userData = __sys.get().userInfoData;
				if(userData){
					_T.loginChk(data);
				}else{
					__sys.on('userInfoData.change?', function(){
						_T.loginChk(data);
					});
				}
			});
		},
		send: function(param) {
			__require('HttpQuery').buy(param, this.bind(function(data) {
				this.buyCallback(data, param);
			}), function() {
				__sys.alert("网络异常，请稍后重试！");
