/*
 * Ajax进行Http请求查询
 * @author  yangxd  
 */
__define('HttpQuery', function(){
	//请求的url
	var urls = {
		buy: '/interface/request.php?q=trade.createorder',
		tmpbuy: '/interface/request.php?q=trade.createtmporder',
		iscanbuy: '/static/public/config/trade/xml/sysexp/1251.xml',
		tzbl_lzc: '/static/public/jczq/json/popularity/lzc/'+__sys.get('expect')+'.json',
		tzbl_szc: '/static/public/jczq/json/popularity/szc/'+__sys.get('expect')+'.json'
	};
	var pause = {};
	/*
	 * 封装了$.ajax方法
	 */
	function send(key, param, fn, cfg) {
		if (pause[key]) {
			return ;
		}
		pause[key] = true;
		return $.ajax($.extend({}, {
			url: urls[key],
			type: 'POST', //默认方法
			dataType: 'json', //默认类型
			data: param,
			success: fn,
			complete: function() {
				setTimeout(function() {
					pause[key] = null;
				}, 1000);
			}
		}, cfg));
	}
	return {
		//投注彩票
		buy: function(param, fn, error) {
			return send('buy', param, fn, {
				error: error
			});
		},
		//投注彩票
		tmpbuy: function(param, fn, error) {
			return send('tmpbuy', param, fn, {
				error: error
			});
		},
		//是否开售查询
		iscanbuy:function(fn){
			return send('iscanbuy', {_: +new Date()},
				function(xml) {
					var flag=$(xml).find('row')[0].getAttribute('Value')==='1'?true:false;
					fn(flag);
				}, {
					type: 'GET',
					dataType: 'xml'
				});
		},
		//用户投注比例
		tzbl: function(lotid, fn, error){
			var key;
			if(lotid == 15){
				key = 'tzbl_lzc';
			}else if(lotid == 17){
				key = 'tzbl_szc';
			}else{
				return false;
			}
			return $.ajax({
				type: "get",
				url : urls[key],
				data: {_: +new Date()},
				dataType: 'text',
				contentType: "application/x-www-form-urlencoded;charset=utf-8;",
				success: function(content, result){
					if(result == 'success' && content){
						fn(content.replace(/[\r\n\s]/g,''));
					}
				},
