/*
 * 数字输入
 */
__defineClass('Number',function() {
	return {
		options: {
			add: 'span.numsel-jia',
			minus: 'span.numsel-jian',
			min: 1,
			max: 9e9,
			mod: 1,
			step: 1,
			tmpl: '{%0}注'
		},
		ui: {
			'{root}': {
				input: {
					name: 'input',
					value: 'valueUpdate, value',
					onkeyup: 'setValue($value)',
					onblur: 'setValue($value, blur)',
					onfocus: 'focus($el)'
				},
				'{add}': {
					onclick: 'add'
				},
				'{minus}': {
					onclick: 'minus'
				}
			}
		},
		minus: function() {
			var val = parseFloat(this.get().value);
			this.setValue(Math.max(this.options.min, val - this.options.step), true);
		},
		add: function() {
			var val = parseFloat(this.get().value);
			this.setValue(Math.min(this.options.max, val + this.options.step), true);
		},
		setValue: function(v, isBlur) {
			var ini = this.options;
			if ($.isString(v)) {
				v = v.replace(/\D/g, '');
			}
			if (v === '') {
				if (isBlur) {
					v = ini.min;
				} else {
					this.set('valueUpdate', '', true);
					return;
				}
			}
			v = Math.min(ini.max, parseFloat(v));
			if (isBlur) {
				v = Math.max(ini.min, v);
			}
			if (this.trigger('beforeChange', v) === false) {
				this.set('value', this.get().value, true);
				return;
			}
			this.set('value', v);
			if (isBlur && ini.templ) {
				v = __sys.format(ini.templ, v);
			}
			this.set('valueUpdate', v, true); //刷新输入框
		},
		focus: function(el) {
			if (this.options.autoSelect) {
				setTimeout(function() {
					el.select();
				},10);
			}
		},
		init: function() {
			//this.ui_input.attr('maxlength', this.options.length || (this.options.max + '').length);
			var value=this.options.defaultValue? this.options.defaultValue:this.options.min;
			this.set('value', value);
		}
	};
});
